1	import { NextResponse } from "next/server";
2	import { readSettings } from "@/lib/settings";
3	import { buildModelId, buildSubmitBody, MAX_BODY_BYTES, resolveBaseUrl, submitTask } from "@/lib/o1key";
4	
5	export const runtime = "nodejs";
6	export const dynamic = "force-dynamic";
7	
8	// Submit one or more generation tasks. Returns the upstream task ids as job ids;
9	// the client polls GET /api/jobs/{id} for each.
10	export async function POST(req: Request) {
11	  const s = await readSettings();
12	  if (!s.apiKey) {
13	    return NextResponse.json({ error: "未设置 API 令牌，请先在设置中填入 o1key 令牌" }, { status: 400 });
14	  }
15	
16	  const body = (await req.json().catch(() => ({}))) as Record<string, unknown>;
17	  const prompt = String(body.prompt ?? "").trim();
18	  const model = String(body.model ?? s.defaults.model);
19	  const resolution = String(body.resolution ?? s.defaults.resolution);
20	  const aspectRatio = String(body.aspectRatio ?? s.defaults.aspectRatio);
21	  const billing = String(body.billing ?? s.defaults.billing);
22	  const count = Math.max(1, Math.min(4, Number(body.count) || 1));
23	  const baseImage = typeof body.baseImage === "string" ? body.baseImage : "";
24	  const refImage = typeof body.refImage === "string" ? body.refImage : "";
25	
26	  if (!prompt) return NextResponse.json({ error: "缺少提示词" }, { status: 400 });
27	  if (!baseImage) return NextResponse.json({ error: "缺少画布底图" }, { status: 400 });
28	
29	  let modelId: string;
30	  try {
31	    modelId = buildModelId(model, resolution, billing);
32	  } catch (e) {
33	    return NextResponse.json({ error: (e as Error).message }, { status: 400 });
34	  }
35	
36	  const images = [baseImage];
37	  if (refImage) images.push(refImage);
38	
39	  const submitBody = buildSubmitBody({ modelId, prompt, resolution, aspectRatio, images });
40	  const bytes = Buffer.byteLength(JSON.stringify(submitBody), "utf-8");
41	  if (bytes > MAX_BODY_BYTES) {
42	    return NextResponse.json(
43	      { error: `请求体 ${(bytes / 1e6).toFixed(1)}MB 超过 20MB 上限，请使用更小的图片` },
44	      { status: 400 },
45	    );
46	  }
47	
48	  const baseUrl = resolveBaseUrl(s.route);
49	  try {
50	    const ids = await Promise.all(
51	      Array.from({ length: count }, () => submitTask(baseUrl, s.apiKey, submitBody)),
52	    );
53	    return NextResponse.json({ jobs: ids.map((id, index) => ({ id, index })), modelId });
54	  } catch (e) {
55	    return NextResponse.json({ error: (e as Error)?.message || "提交失败" }, { status: 502 });
56	  }
57	}
58

